const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_UNIT_BASE = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

// A run of N alike components is priced as floor(N/3) blocks of 3 (at COMPONENT_BLOCK_BASE each)
// plus the leftover priced per unit.
const componentBundleBase = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const leftover = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_BASE + leftover * COMPONENT_UNIT_BASE;
};

// Each "billing group" is one main item or one bundle of alike components.
const billingGroupBases = (items: Item[]): number[] => {
  const bases: number[] = [];
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      bases.push(MAIN_ITEM_BASE_PREMIUM[item.type]);
    }
  }
  for (const count of componentCounts.values()) {
    bases.push(componentBundleBase(count));
  }
  return bases;
};

const withFirstInsurance = (base: number): number => base * (1 + FIRST_INSURANCE_RATE);

const quotePremium = (items: Item[]): number => {
  const groupBases = billingGroupBases(items);
  const itemsTotal = groupBases.reduce((sum, base) => sum + withFirstInsurance(base), 0);
  return itemsTotal + PROCESSING_FEE;
};

